// Récupérer le fichier uploadé depuis le formulaire
const formData = $input.first().json;
const tournoi_id = parseInt(formData['Tournoi ID']) || 1;

// Le fichier est dans les binary data
const binaryKey = Object.keys($input.first().binary || {})[0];

if (!binaryKey) {
  throw new Error('Aucun fichier trouvé dans le formulaire');
}

return [{
  json: { tournoi_id },
  binary: $input.first().binary
}];

// Conversion date Excel → ISO
function excelDateToISO(excelDate) {
  if (!excelDate) return null;
  if (typeof excelDate === 'string' && excelDate.includes('-')) return excelDate;
  if (excelDate instanceof Date) return excelDate.toISOString();
  const date = new Date((excelDate - 25569) * 86400 * 1000);
  return date.toISOString();
}

const items = [];
let tournoi_id = 1;
try {
  tournoi_id = parseInt($('Préparer le fichier').first().json.tournoi_id) || 1;
} catch(e) {}

for (const item of $input.all()) {
  const row = item.json;
  if (!row['Numéro de billet']) continue;

  // Email et Téléphone sont des champs variables HelloAsso (col Q+) → custom_fields
  const inscription = {
    numero_billet:      parseInt(row['Numéro de billet']),
    tournoi_id:         tournoi_id,
    reference_commande: parseInt(row['Référence commande']) || null,
    date_commande:      excelDateToISO(row['Date de la commande']),
    statut_commande:    row['Statut de la commande'] || null,
    nom_participant:    row['Nom participant'] || null,
    prenom_participant: row['Prénom participant'] || null,
    nom_payeur:         row['Nom payeur'] || null,
    prenom_payeur:      row['Prénom payeur'] || null,
    email_payeur:       row['Email payeur'] || null,
    moyen_paiement:     row['Moyen de paiement'] || null,
    tarif:              row['Tarif'] || null,
    montant_tarif:      parseFloat(row['Montant tarif']) || null,
    code_promo:         row['Code Promo'] || null,
    montant_code_promo: parseFloat(row['Montant code promo']) || null,
    custom_fields: Object.fromEntries(
      Object.entries({
        email:          row['Email'] || null,
        telephone:      row['Téléphone'] || null,
        equipe:         row['Equipe'] || null,
        niveau_equipe:  row["Niveau de l'équipe"] || null,
        nom_equipe:     row["Nom d'équipe"] || null,
        clubs_origine:  row["Club(s) d'origine"] || null,
        commentaire:    row['Commentaire éventuel'] || null,
        liste_campeurs: row['Liste des campeurs'] || null
      }).filter(([_, v]) => v !== null)
    )
  };

  items.push({ json: inscription });
}

return items;

const results = $input.all();
const success = results.filter(r => !r.json.error).length;
const errors  = results.filter(r =>  r.json.error).length;

console.log(`Import terminé : ${success} succès, ${errors} erreurs`);

return [{
  json: {
    message: '✅ Import terminé',
    total_traite: results.length,
    succes: success,
    erreurs: errors,
    timestamp: new Date().toISOString()
  }
}];
